const MODEL_MODE = isDeepAnalysis ? 'opus_deep' : 'sonnet_default';
const MAX_TOKENS = isDeepAnalysis ? 4096 : 2048;

const RATES = {
  'claude-opus-4-6':   { input: 0.000015, output: 0.000075 },
  'claude-sonnet-4-6': { input: 0.000003, output: 0.000015 }
};

let atlasSystemPrompt = systemPrompt;
try {
  const promptPath = '/data/Atlas_System_Prompt.txt';
  if (fs.existsSync(promptPath)) {
    atlasSystemPrompt = fs.readFileSync(promptPath, 'utf8');
  }
} catch(e) {}

const requestBody = JSON.stringify({
  model: MODEL,
  max_tokens: MAX_TOKENS,
  system: atlasSystemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
});

const ANTHROPIC_KEY = $env.ANTHROPIC_API_KEY || '';

const apiOptions = {
  hostname: 'api.anthropic.com',
  port: 443,
  path: '/v1/messages',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'x-api-key': ANTHROPIC_KEY,
    'anthropic-version': '2023-06-01',
    'Content-Length': Buffer.byteLength(requestBody)
  }
};

const result = await new Promise((resolve, reject) => {
  const req = https.request(apiOptions, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ status: res.statusCode, body: d }));
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

