  if (!SUPA_URL || !SUPA_KEY) return null;
  const body = JSON.stringify(payload);
  const urlStr = `${SUPA_URL}/rest/v1/${table}`;
const hostname = SUPA_URL.replace('https://', '').replace('http://', '');
const path = `/rest/v1/${table}`;
