  outputTokens = parsed.usage?.output_tokens || 0;
} catch(e) {
  fullText = result.body.substring(0, 500);
}

const rate = RATES[MODEL] || RATES['claude-sonnet-4-6'];
const costUsd = (inputTokens * rate.input) + (outputTokens * rate.output);

const wordCount = fullText.split(/\s+/).filter(w => w.length > 0).length;
const dateStr = new Date(timestamp).toISOString().slice(0, 10).replace(/-/g, '');
